#include <stdio.h>
int main() {
    int N, T, Li, Ri, Mi;
    scanf("%d", &N);
    int arr[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &Li, &Ri, &Mi);
        long long product = 1;
        for (int i = Li - 1; i < Ri; i++) {
            product = (product * arr[i]) % Mi;
        }
        printf("%lld\n", product);
    }
    return 0;
}

